import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F02_營業現金流與獲利品質.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F02_營業現金流與獲利品質.md"}'),i={name:"審計報告庫/財務審計/6239_力成/20260617/F02_營業現金流與獲利品質.md"};function o(n,a,h,s,d,_){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="f02-營業現金流與獲利品質-財務審計專家報告" tabindex="-1">F02: 營業現金流與獲利品質 - 財務審計專家報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-財務審計專家報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CFO/NI達716%，獲利含金量極高，但主因折舊122.3億。FCF轉負-93.3億，CapEx 259.4億創新高，現金被擴產吞噬。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>2022-2025各年度CFO分別為229.2億→196.8億→215.7億→167.0億，均大幅超越稅後淨利。CFO/NI比值分別為1,445%/452%/1,119%/716%，遠高於製造業100%合理門檻。但需注意CFO高比值的主因是折舊費用龐大（2025年122.3億，佔CFO的73%），而非營運資金效率出眾。自由現金流從2024年的+117.0億驟降至2025年的-93.3億，主因CapEx由113.8億暴衝至259.4億擴產投資，獲利含金量雖高但現金被資本支出大量吞噬。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="獲利含金量穿透" tabindex="-1">獲利含金量穿透 <a class="header-anchor" href="#獲利含金量穿透" aria-label="Permalink to &quot;獲利含金量穿透&quot;">​</a></h3><p>力成2025年合併稅後淨利72.2億（歸屬母公司51.4億），CFO達167.0億，CFO/NI比值716%，表面上看含金量極高。但拆解現金流量表：折舊費用122.3億是CFO最大來源（佔73.3%），其次才是本業獲利貢獻。折舊係非現金項目，因此用CFO/NI判斷含金量在半導體封測業需要校正——高折舊使比值天然偏高。應收帳款增加31.4億、存貨增加11.2億為當年營運資金流出主因。</p><h3 id="自由現金流穿越" tabindex="-1">自由現金流穿越 <a class="header-anchor" href="#自由現金流穿越" aria-label="Permalink to &quot;自由現金流穿越&quot;">​</a></h3><p>2025年FCF從2024年+117.0億急轉為-93.3億，是近年最低水準。主因是2025年CapEx暴增至259.4億（前年113.8億，+128%），用於先進封裝（FOPLP、HBM相關設備）擴產。公司舉借長期借款144.5億應對資金需求，2025年底現金餘額由222.4億降至163.8億。從附註揭露，114年2月至115年2月間購置機器設備合約總金額約60億以上，資本支出高峰尚未結束。</p><h3 id="折舊掩蓋診斷" tabindex="-1">折舊掩蓋診斷 <a class="header-anchor" href="#折舊掩蓋診斷" aria-label="Permalink to &quot;折舊掩蓋診斷&quot;">​</a></h3><p>假設扣除折舊122.3億後，CFO僅剩44.7億，約當稅後淨利的62%。2025年稅前淨利87.9億，扣除折舊前的營運現金流為290.5億，但扣除折舊後會發現本業的實質現金回收能力其實不如CFO/NI比值暗示的那麼強勁。力成屬於「高折舊型現金流」—大量前期投資透過折舊回收現金，但同時也需要持續投入巨額CapEx維持產能競爭力。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>FCF轉負警訊</strong>：2025年FCF-93.3億，CapEx 259.4億（+128%），擴產速度遠超現金回收。若2026年營收未達預期，FCF恐連續為負增加融資壓力。</li><li><strong>現金快速消耗</strong>：現金從222.4億降至163.8億（-26.3%），2026年CapEx 400億以上，帳上163億加CFO~140億仍難完全支應。</li><li><strong>折舊侵蝕實質利潤</strong>：折舊122.3億（+28.6%），折舊/營收比13.6%→16.3%。2027-2028年折舊攤提高峰若產能率&lt;85%，將侵蝕大部分毛利。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>CFO穩健</strong>：每年穩定提供130-167億現金流入，擴產結束後將直接轉為FCF。</li><li><strong>投資回報合理</strong>：CapEx用於先進封裝（FOPLP年產5.9萬片），2027年營收貢獻50-80億/年，回收期4-6年符合半導體設備週期。</li><li><strong>折舊稅盾效應</strong>：折舊為非現金費用，減少稅負。2027年後CapEx放緩，FCF可望大幅改善。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>FCF轉負是策略性擴產的階段性現象。關鍵觀察點在於2026-2027年營收能否成長消化產能。若新產能順利量產FCF將於2027年後回正，否則折舊將持續侵蝕帳面利潤。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (cashflow_quality 6239)</li><li>原始數據：FinMind TaiwanStockCashFlowsStatement</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 12-13，現金流量表)</li><li>年報數據：2024_Q4_6239_合併.pdf (pages 12-13)</li><li>法說會資訊：富果法說會備忘錄 20260428</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const u=e(i,[["render",o]]);export{F as __pageData,u as default};
